SELECT state_name, total_confirmed_cases, deaths
FROM states
ORDER BY total_confirmed_cases DESC;

SELECT COUNT(center_id) AS center_count
FROM vaccination_centers
WHERE state_id = 0;

SELECT state_name
FROM states
ORDER BY state_name ASC;

SELECT DISTINCT v.vaccination_date
FROM vaccination_data v
JOIN trends t ON v.vaccination_date = t.report_date;

SELECT state_id, AVG(capacity) AS avg_capacity
FROM vaccination_centers
GROUP BY state_id;

SELECT state_name, total_confirmed_cases
FROM states
ORDER BY total_confirmed_cases DESC;

SELECT COUNT(*) AS hospital_count
FROM hospital_data
WHERE state_id = 1;
